const menuToggle = document.querySelector("[data-menu-toggle]");const mobileMenu = document.querySelector("[data-mobile-menu]");const mobileLinks = document.querySelectorAll(".mobile-nav a,.mobile-menu .button");const siteHeader = document.querySelector("[data-site-header]");function setMenuState(isOpen){if(!menuToggle || !mobileMenu)return;menuToggle.setAttribute("aria-expanded",String(isOpen));menuToggle.setAttribute("aria-label",isOpen ? "Tutup menu":"Buka menu");mobileMenu.hidden = !isOpen;document.body.classList.toggle("menu-open",isOpen);}menuToggle?.addEventListener("click",()=>{const isOpen = menuToggle.getAttribute("aria-expanded")=== "true";setMenuState(!isOpen);});mobileLinks.forEach((link)=>{link.addEventListener("click",()=> setMenuState(false));});window.addEventListener("keydown",(event)=>{if(event.key === "Escape"){setMenuState(false);}});window.addEventListener("resize",()=>{if(window.matchMedia("(min-width:1024px)").matches){setMenuState(false);}});function updateHeaderState(){siteHeader?.classList.toggle("is-scrolled",window.scrollY > 10);}updateHeaderState();window.addEventListener("scroll",updateHeaderState,{passive:true});const revealItems = document.querySelectorAll(".section-header,.problem-card,.problem-closing,.service-card,.detail-card,.reason-list article,.highlight-card,.process-step,.cta-panel");if(revealItems.length && "IntersectionObserver" in window){document.body.classList.add("reveal-ready");revealItems.forEach((item)=> item.classList.add("reveal-item"));const revealObserver = new IntersectionObserver((entries,observer)=>{entries.forEach((entry)=>{if(!entry.isIntersecting)return;entry.target.classList.add("is-visible");observer.unobserve(entry.target);});},{threshold:0.12,rootMargin:"0px 0px -8% 0px"});revealItems.forEach((item)=> revealObserver.observe(item));}